import{_ as t,c as r,o as a,ag as i}from"./chunks/framework.DPDPlp3K.js";const h=JSON.parse('{"title":"Introduction to WebUI Framework","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),n={name:"guide/index.md"};function o(s,e,l,p,d,c){return a(),r("div",null,e[0]||(e[0]=[i('<h1 id="introduction-to-webui-framework" tabindex="-1">Introduction to WebUI Framework <a class="header-anchor" href="#introduction-to-webui-framework" aria-label="Permalink to &quot;Introduction to WebUI Framework&quot;">​</a></h1><h2 id="reimagining-web-development" tabindex="-1">Reimagining Web Development <a class="header-anchor" href="#reimagining-web-development" aria-label="Permalink to &quot;Reimagining Web Development&quot;">​</a></h2><p>WebUI Framework was born from a simple question: What if we could build web applications without the overhead that modern JavaScript frameworks impose?</p><p>The web platform was designed with clear separation of concerns - HTML for structure, CSS for presentation, and JavaScript for behavior. Yet somewhere along the way, we ended up with JavaScript frameworks that do everything, often at the expense of performance and simplicity.</p><h2 id="the-problem-with-traditional-js-frameworks" tabindex="-1">The Problem With Traditional JS Frameworks <a class="header-anchor" href="#the-problem-with-traditional-js-frameworks" aria-label="Permalink to &quot;The Problem With Traditional JS Frameworks&quot;">​</a></h2><p>Modern web development has strayed far from the web&#39;s original design:</p><ul><li><p><strong>JavaScript Wasn&#39;t Built to Be a UI Framework</strong>: JavaScript was designed as a lightweight scripting language to add interactivity, not to manage the entire rendering pipeline.</p></li><li><p><strong>Tangled Concerns</strong>: CSS-in-JS, HTML-in-JS, and JSX blur the lines between structure, style, and logic, making codebases harder to maintain and understand.</p></li><li><p><strong>Client-Side Rendering Costs</strong>: Shipping megabytes of JavaScript to be parsed and executed by browsers creates poor initial loading experiences and hurts performance metrics.</p></li><li><p><strong>Runtime Overhead</strong>: Every interaction requires JavaScript to recalculate state, rebuild the DOM, and update the UI - creating unnecessary work for both servers and browsers.</p></li></ul><h2 id="webui-s-approach-back-to-fundamentals-forward-to-performance" tabindex="-1">WebUI&#39;s Approach: Back to Fundamentals, Forward to Performance <a class="header-anchor" href="#webui-s-approach-back-to-fundamentals-forward-to-performance" aria-label="Permalink to &quot;WebUI&#39;s Approach: Back to Fundamentals, Forward to Performance&quot;">​</a></h2><p>WebUI Framework returns to the web platform&#39;s core strengths while embracing modern needs:</p><ul><li><p><strong>Separation of Concerns</strong>: HTML templates are HTML, CSS is CSS, and JavaScript is for enhancing interactivity - not recreating the browser&#39;s rendering engine.</p></li><li><p><strong>Build-Time Optimization</strong>: WebUI separates static and dynamic content at build time, creating an efficient protocol that dramatically reduces runtime costs.</p></li><li><p><strong>Islands of Interactivity</strong>: Following the &quot;Islands Architecture,&quot; we keep most of the page static and fast, with interactive components only where needed.</p></li><li><p><strong>Language-Agnostic Backend</strong>: Whether you use Rust, Go, C#, PHP, Ruby, or any other server language, WebUI works without requiring a Node.js runtime.</p></li></ul><h2 id="real-benefits-you-ll-experience" tabindex="-1">Real Benefits You&#39;ll Experience <a class="header-anchor" href="#real-benefits-you-ll-experience" aria-label="Permalink to &quot;Real Benefits You&#39;ll Experience&quot;">​</a></h2><ul><li><p><strong>Lightning-Fast Performance</strong>: By minimizing JavaScript execution and optimizing for key web vitals, users experience near-instant page loads.</p></li><li><p><strong>Simplified Development</strong>: Write templates as templates, styles as styles, and focus your JavaScript just on what&#39;s interactive.</p></li><li><p><strong>Universal Server Support</strong>: No more JavaScript backend requirements - use the language and server infrastructure you prefer.</p></li><li><p><strong>Reduced Bundle Sizes</strong>: Send just the state data, not entire rendering libraries or HTML strings.</p></li><li><p><strong>Better SEO and Accessibility</strong>: Pre-rendered content ensures search engines and assistive technologies can easily interpret your pages.</p></li></ul><h2 id="how-is-this-possible" tabindex="-1">How Is This Possible? <a class="header-anchor" href="#how-is-this-possible" aria-label="Permalink to &quot;How Is This Possible?&quot;">​</a></h2><p>WebUI takes a fundamentally different approach:</p><ol><li>At <strong>build time</strong>, WebUI analyzes your components and creates an efficient protocol separating static from dynamic content</li><li>At <strong>runtime</strong>, your server applies state to this protocol with minimal computation</li><li>In the <strong>browser</strong>, content arrives mostly pre-rendered and ready to display</li></ol><p>This means pages load faster, servers require less processing power, and developers can work with a more intuitive separation of concerns.</p><p>Ready to see how it works in practice? Let&#39;s start building with WebUI Framework!</p>',17)]))}const m=t(n,[["render",o]]);export{h as __pageData,m as default};
